import React, { useState, useEffect } from 'react';
import { Box } from '@mui/material';
import FAWThemeProvider from '../../../Theme/FAWThemeProvider';
import FAWDrawer from '../../FAWDrawer';
import FAWLoader from '../../FAWLoader';
import FAWInput from '../../FAWInput';
import FAWTextarea from '../../FAWTextarea';
import FAWDropdown from '../../FAWDropdown';
import FAWCheckbox from '../../FAWCheckbox';
import FAWTypography from '../../FAWTypography';
import FAWAlert from '../../FAWAlert';
import FAWToast from '../../FAWToast';
import DatePicker from 'react-datepicker';
import moment from 'moment';
import 'react-datepicker/dist/react-datepicker.css';
import '../../../Base/Style/datepicker.css';

/**
 * Field Editor Drawer Component
 * Provides a form interface for creating and editing additional field definitions
 */
const FieldEditorDrawer = ({ 
  open, 
  onClose, 
  fieldData, 
  onSave,
  fieldId,
  category,
  dataTypeOptions: initialDataTypeOptions = [],
  domainOptions: initialDomainOptions = [],
  optionsLoading = false,
  existingFields = [] // Array of existing field names to check for duplicates
}) => {
  const [formData, setFormData] = useState({
    Id: 0,
    Name: '',
    PersistedName: '',
    LockId: 0,
    Description: '',
    DataTypeCode: '',
    DomainCode: '',
    Active: false,
    IsReadOnly: false,
    DefaultValue: '',
    DefaultValueCode: '',
    DefaultValues: [],
    MaxTextLength: 0,
    MultiLineNumber: 0,
    LowRange: '',
    HighRange: '',
    DecimalPlacesNumber: 0,
    AllowNegativeValues: false,
    FormatMask: '',
    RelateClassName: ''
  });

  const [errors, setErrors] = useState({});
  const [saving, setSaving] = useState(false);
  const [loadingModel, setLoadingModel] = useState(false);
  const [toast, setToast] = useState({
    open: false,
    message: '',
    type: 'info' // 'success', 'error', 'warning', 'info'
  });
  const [dataTypeOptions, setDataTypeOptions] = useState(initialDataTypeOptions || []);
  const [domainOptions, setDomainOptions] = useState(initialDomainOptions || []);
  const [defaultValueOptions, setDefaultValueOptions] = useState([]);
  const [loadingDefaults, setLoadingDefaults] = useState(false);
  // Dynamic CSV attributes for conditional field visibility (Gap Fix #1)
  const [requiresFormatPatternCSV, setRequiresFormatPatternCSV] = useState('');
  const [requiresAllowNegativeCSV, setRequiresAllowNegativeCSV] = useState('');
  const [requiresNumberOfLinesCSV, setRequiresNumberOfLinesCSV] = useState('');

  const getCsrfToken = () => {
    return document.querySelector('input[name="__RequestVerificationToken"]')?.value || null;
  };

  const extractStringValue = (val) => {
    if (!val) return '';
    if (typeof val === 'string') return val;
    if (typeof val === 'object') {
      return val.Value !== undefined ? String(val.Value) :
             (val.value !== undefined ? String(val.value) :
             (val.Domain !== undefined ? String(val.Domain) : ''));
    }
    return String(val);
  };

  const normalizeOptions = (options) => {
    if (!Array.isArray(options)) return [];
    return options.map(opt => {
      if (typeof opt === 'string') {
        return { value: opt, label: opt };
      }
      const value = opt.Value !== undefined ? opt.Value : (opt.value !== undefined ? opt.value : '');
      const label = opt.Text !== undefined ? opt.Text : 
                   (opt.Meaning !== undefined ? opt.Meaning : 
                   (opt.label !== undefined ? opt.label : 
                   (opt.text !== undefined ? opt.text : String(value))));
      return { value, label };
    });
  };

  useEffect(() => {
    if (initialDataTypeOptions?.length > 0) {
      setDataTypeOptions(initialDataTypeOptions);
    }
    if (initialDomainOptions?.length > 0) {
      setDomainOptions(initialDomainOptions);
    }
  }, [initialDataTypeOptions, initialDomainOptions]);

  useEffect(() => {
    if (!open || fieldId === undefined || fieldId === null) return;

    const loadFieldData = async () => {
      try {
        const headers = { 'Content-Type': 'application/x-www-form-urlencoded' };
        const token = getCsrfToken();
        if (token) headers['RequestVerificationToken'] = token;

        if (Number(fieldId) > 0) {
          setLoadingModel(true);
          const params = new URLSearchParams({ id: String(fieldId) });
          if (category) params.append('category', category);
          
          const resp = await fetch('/RelatedDataDef/GetFieldForEditApi', { 
            method: 'POST', 
            headers, 
            body: params 
          });
          const data = await resp.json();
          
          if (!data?.success) {
            throw new Error(data?.error || data?.message || 'Failed to load field');
          }

          const model = data.field || {};
          setFormData(prev => ({
            ...prev,
            Id: model.Id || 0,
            PersistedName: model.PersistedName || model.Name || '',
            LockId: model.LockId || 0,
            Name: model.Name || '',
            Description: model.Description || '',
            DataTypeCode: extractStringValue(model.DataTypeCode),
            DomainCode: extractStringValue(model.DomainCode),
            Active: model.Active !== undefined ? model.Active : false,
            IsReadOnly: model.IsReadOnly || false,
            DefaultValue: model.DefaultValue || '',
            DefaultValueCode: extractStringValue(model.DefaultValueCode),
            DefaultValues: model.DefaultValues || [],
            MaxTextLength: model.MaxTextLength || 0,
            MultiLineNumber: model.MultiLineNumber || 0,
            LowRange: model.LowRange != null ? String(model.LowRange) : '',
            HighRange: model.HighRange != null ? String(model.HighRange) : '',
            DecimalPlacesNumber: model.DecimalPlacesNumber || 0,
            AllowNegativeValues: model.AllowNegativeValues || false,
            FormatMask: model.FormatMask || '',
            RelateClassName: model.RelateClassName || category || ''
          }));
          
          setDataTypeOptions(model.DataTypeOptions || []);
          setDomainOptions(model.DomainOptions || []);
          setDefaultValueOptions(model.DefaultValueOptions || []);
          setRequiresFormatPatternCSV(model.RequiresFormatPatternCSV || '');
          setRequiresAllowNegativeCSV(model.RequiresAllowNegativeCSV || '');
          setRequiresNumberOfLinesCSV(model.RequiresNumberOfLinesCSV || '');
        } else {
          setDataTypeOptions(initialDataTypeOptions || []);
          setDomainOptions(initialDomainOptions || []);
          

          setLoadingDefaults(true);
          try {
            const params = new URLSearchParams();
            if (category) params.append('domainCode', category);
            const resp = await fetch('/RelatedDataDef/GetFieldOptionsApi', { 
              method: 'POST', 
              headers, 
              body: params 
            });
            const data = await resp.json();
            if (data?.success) {
              setDefaultValueOptions(data.defaultValueOptions || []);
              setRequiresFormatPatternCSV(data.RequiresFormatPatternCSV || '');
              setRequiresAllowNegativeCSV(data.RequiresAllowNegativeCSV || '');
              setRequiresNumberOfLinesCSV(data.RequiresNumberOfLinesCSV || '');
            }
          } catch (e) {
            console.error('Failed to load field options:', e);
          } finally {
            setLoadingDefaults(false);
          }
          
          if (!category) {
            setDefaultValueOptions([]);
          }
          
          setFormData(prev => ({ 
            ...prev, 
            Id: 0, 
            Name: '', 
            Description: '', 
            DataTypeCode: 'String', // Default to String
            Active: true, // Default to true 
            IsReadOnly: false, 
            RelateClassName: category || '' 
          }));
        }
      } catch (e) {
        console.error('FieldEditorDrawer fetch error:', e);
        setErrors({ general: 'Failed to load field. Please try again.' });
      } finally {
        setLoadingModel(false);
      }
    };

    loadFieldData();
  }, [open, fieldId, initialDataTypeOptions, initialDomainOptions, category]);

  useEffect(() => {
    if (!open) return;
    
    const domainBased = formData.DataTypeCode === 'Domain' || formData.DataTypeCode === 'MULTILIST';
    if (!domainBased) {
      if (defaultValueOptions.length > 0) setDefaultValueOptions([]);
      return;
    }
    if (!formData.DomainCode) return;

    const loadDefaultValueOptions = async () => {
      try {
        setLoadingDefaults(true);
        const headers = { 'Content-Type': 'application/x-www-form-urlencoded' };
        const token = getCsrfToken();
        if (token) headers['RequestVerificationToken'] = token;
        
        const params = new URLSearchParams({ domainCode: formData.DomainCode });
        const resp = await fetch('/RelatedDataDef/GetFieldOptionsApi', { 
          method: 'POST', 
          headers, 
          body: params 
        });
        const data = await resp.json();
        if (data?.success) {
          setDefaultValueOptions(data.defaultValueOptions || []);
        }
      } catch (e) {
        console.error('Failed to load default value options:', e);
      } finally {
        setLoadingDefaults(false);
      }
    };

    loadDefaultValueOptions();
  }, [open, formData.DataTypeCode, formData.DomainCode]);

  useEffect(() => {
    if (!fieldData) return;
    
    setFormData({
      Id: fieldData.Id || 0,
      Name: fieldData.Name || '',
      Description: fieldData.Description || '',
      DataTypeCode: extractStringValue(fieldData.DataTypeCode) || ((fieldData.Id || 0) === 0 ? 'String' : ''), // Default to String for new fields (matching legacy)
      DomainCode: extractStringValue(fieldData.DomainCode),
      Active: fieldData.Active !== undefined ? fieldData.Active : ((fieldData.Id || 0) === 0 ? true : false), // Default to true for new fields (matching legacy UI)
      IsReadOnly: fieldData.IsReadOnly || false,
      DefaultValue: fieldData.DefaultValue || '',
      DefaultValueCode: extractStringValue(fieldData.DefaultValueCode),
      DefaultValues: fieldData.DefaultValues || [],
      MaxTextLength: fieldData.MaxTextLength || 0,
      MultiLineNumber: fieldData.MultiLineNumber || 0,
      LowRange: fieldData.LowRange || '',
      HighRange: fieldData.HighRange || '',
      DecimalPlacesNumber: fieldData.DecimalPlacesNumber || 0,
      AllowNegativeValues: fieldData.AllowNegativeValues || false,
      FormatMask: fieldData.FormatMask || '',
      RelateClassName: fieldData.RelateClassName || category || ''
    });
    if (fieldData.RequiresFormatPatternCSV !== undefined) {
      setRequiresFormatPatternCSV(fieldData.RequiresFormatPatternCSV || '');
    }
    if (fieldData.RequiresAllowNegativeCSV !== undefined) {
      setRequiresAllowNegativeCSV(fieldData.RequiresAllowNegativeCSV || '');
    }
    if (fieldData.RequiresNumberOfLinesCSV !== undefined) {
      setRequiresNumberOfLinesCSV(fieldData.RequiresNumberOfLinesCSV || '');
    }
  }, [fieldData, category]);

  // Reset form when drawer closes
  useEffect(() => {
    if (!open) {
      // Reset form data to defaults when drawer closes
      setFormData({
        Id: 0,
        Name: '',
        PersistedName: '',
        LockId: 0,
        Description: '',
        DataTypeCode: '',
        DomainCode: '',
        Active: false,
        IsReadOnly: false,
        DefaultValue: '',
        DefaultValueCode: '',
        DefaultValues: [],
        MaxTextLength: 0,
        MultiLineNumber: 0,
        LowRange: '',
        HighRange: '',
        DecimalPlacesNumber: 0,
        AllowNegativeValues: false,
        FormatMask: '',
        RelateClassName: ''
      });
      // Clear errors
      setErrors({});
      // Reset CSV attributes
      setRequiresFormatPatternCSV('');
      setRequiresAllowNegativeCSV('');
      setRequiresNumberOfLinesCSV('');
      setDefaultValueOptions([]);
    }
  }, [open]);

  const handleInputChange = (field, value) => {
    setFormData(prev => ({
      ...prev,
      [field]: value
    }));
    
    // Clear error when user starts typing
    if (errors[field]) {
      setErrors(prev => ({
        ...prev,
        [field]: ''
      }));
    }
  };

  const handleCheckboxChange = (field, checked) => {
    setFormData(prev => ({
      ...prev,
      [field]: checked
    }));
  };

  const handleDefaultValueChange = (value, checked) => {
    setFormData(prev => ({
      ...prev,
      DefaultValues: checked 
        ? [...prev.DefaultValues, value]
        : prev.DefaultValues.filter(v => v !== value)
    }));
  };

  /**
   * Helper function to check if a field name is duplicate
   * @param {string} name - The field name to check
   * @param {number} currentFieldId - The ID of the current field being edited (0 for new fields)
   * @param {Array} fields - Array of existing fields to check against
   * @returns {boolean} - True if duplicate found, false otherwise
   */
  const isDuplicateFieldName = (name, currentFieldId, fields) => {
    if (!name || !name.trim()) {
      return false;
    }
    
    // Guard against null/undefined fields array
    if (!fields || !Array.isArray(fields) || fields.length === 0) {
      return false;
    }
    
    const trimmedName = name.trim();
    return fields.some(field => {
      // For new fields (Id === 0), check if name exists
      // For editing fields, check if name exists AND it's a different field
      const isSameName = field.Name && field.Name.trim().toLowerCase() === trimmedName.toLowerCase();
      const isDifferentField = field.Id !== currentFieldId;
      return isSameName && (currentFieldId === 0 || isDifferentField);
    });
  };

  const validateForm = () => {
    const newErrors = {};
    
    // Required field: Name
    if (!formData.Name.trim()) {
      newErrors.Name = 'Name cannot be empty';
    } else if (isDuplicateFieldName(formData.Name, formData.Id, existingFields)) {
      newErrors.Name = 'This field name is already in use. Please choose a different name.';
    }
    
    // Required field: Data Type
    if (!formData.DataTypeCode) {
      newErrors.DataTypeCode = 'Data Type is required';
    }

    // Domain Code: Required when Domain or MULTILIST is selected
    if (isDomainType && !formData.DomainCode) {
      newErrors.DomainCode = 'Data Domain is required';
    }

    // Max Text Length: Range(0, 1000) - only for String type
    if (formData.DataTypeCode === 'String') {
      const maxLength = parseInt(formData.MaxTextLength) || 0;
      if (maxLength <= 0) {
        newErrors.MaxTextLength = 'Max Text Length must be greater than 0';
      } else if (maxLength > 1000) {
        newErrors.MaxTextLength = 'Length must be between 0 and 1000';
      }
    }

    // Number of Lines: Range(0, 10) - only when visible
    if (showMultiLineNumber) {
      const multiLineNum = parseInt(formData.MultiLineNumber) || 0;
      if (multiLineNum < 0 || multiLineNum > 10) {
        newErrors.MultiLineNumber = 'Length must be between 0 and 10';
      }
    }

    // Numeric type validations
    if (formData.DataTypeCode === 'Numeric') {
      // Low Range: Range(-1000000000, 1000000000)
      if (formData.LowRange !== '' && formData.LowRange != null) {
        const lowRange = parseFloat(formData.LowRange);
        if (isNaN(lowRange) || lowRange < -1000000000 || lowRange > 1000000000) {
          newErrors.LowRange = 'Low Value must be between -1000000000 and 1000000000';
        }
      }

      // High Range: Range(0, 1000000000) and must be > Low Range
      if (formData.HighRange !== '' && formData.HighRange != null) {
        const highRange = parseFloat(formData.HighRange);
        if (isNaN(highRange) || highRange < 0 || highRange > 1000000000) {
          newErrors.HighRange = 'High Value must be between 0 and 1000000000';
        } else if (formData.LowRange !== '' && formData.LowRange != null) {
          const lowRange = parseFloat(formData.LowRange);
          if (!isNaN(lowRange) && highRange <= lowRange) {
            newErrors.HighRange = 'High Range must be greater than Low Range';
          }
        }
      }
    }

    // Decimal Precision: Range(0, 10) - for Numeric and DECIMAL types
    if (isNumericType || isDecimalType) {
      const decimalPlaces = parseInt(formData.DecimalPlacesNumber) || 0;
      if (decimalPlaces < 0 || decimalPlaces > 10) {
        newErrors.DecimalPlacesNumber = 'Length must be between 0 and 10';
      }
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSave = async () => {
    if (!validateForm()) {
      // Show toast notification for validation errors
      setToast({
        open: true,
        message: 'Please fix validation errors before saving',
        type: 'error'
      });
      return;
    }

    setSaving(true);
    setErrors({});
    
    try {
      const payload = {
        Id: formData.Id || 0,
        PersistedName: formData.PersistedName || formData.Name || '',
        LockId: formData.LockId || 0,
        Name: formData.Name || '',
        Description: formData.Description || '',
        DataTypeCode: formData.DataTypeCode || '',
        DomainCode: formData.DomainCode || '',
        Active: formData.Active,
        IsReadOnly: formData.IsReadOnly,
        RelateClassName: 'WorkflowTaskDefinition', // Always set to WorkflowTaskDefinition
        MaxTextLength: formData.MaxTextLength || 0,
        MultiLineNumber: formData.MultiLineNumber || 0,
        DecimalPlacesNumber: formData.DecimalPlacesNumber || 0,
        AllowNegativeValues: formData.AllowNegativeValues || false,
        FormatMask: formData.FormatMask || '',
        // Include Category as RelatedData so it can be queried later
        RelatedDatas: [
          {
            Name: 'Category',
            Value: category || ''
          }
        ]
      };

      if (formData.DataTypeCode === 'Numeric') {
        payload.LowRange = formData.LowRange ? parseFloat(formData.LowRange) : null;
        payload.HighRange = formData.HighRange ? parseFloat(formData.HighRange) : 0;
      } else {
        payload.HighRange = 0;
      }

      if (formData.DataTypeCode === 'Domain') {
        payload.DefaultValueCode = formData.DefaultValueCode || '';
      } else if (formData.DataTypeCode === 'MULTILIST') {
        payload.DefaultValues = formData.DefaultValues || [];
      } else {
        payload.DefaultValue = formData.DefaultValue || '';
      }

      const headers = { 'Content-Type': 'application/json' };
      const token = getCsrfToken();
      if (token) headers['RequestVerificationToken'] = token;

      const response = await fetch('/RelatedDataDef/SaveFieldApi', {
        method: 'POST',
        headers,
        body: JSON.stringify(payload)
      });

      if (!response.ok) {
        throw new Error(`Save failed with status: ${response.status}`);
      }

      const result = await response.json();
      
      if (result?.success) {
        // Show success toast
        setToast({
          open: true,
          message: formData.Id ? 'Field updated successfully' : 'Field created successfully',
          type: 'success'
        });
        
        if (onSave) {
          try {
            await onSave(formData);
          } catch (refreshError) {
            console.warn('Error refreshing after save:', refreshError);
          }
        }
        
        // Close drawer after a short delay to show the toast
        setTimeout(() => {
          onClose();
        }, 500);
      } else {
        const errorMsg = result?.message || 'Failed to save field';
        throw new Error(errorMsg);
      }
    } catch (error) {
      console.error('Error saving field:', error);
      const errorMessage = error?.message || 'Failed to save field. Please try again.';
      
      // Show error in form
      setErrors({ general: errorMessage });
      
      // Show error toast
      setToast({
        open: true,
        message: errorMessage,
        type: 'error'
      });
    } finally {
      setSaving(false);
    }
  };

  const isDomainType = formData.DataTypeCode === 'Domain' || formData.DataTypeCode === 'MULTILIST';
  const isStringType = formData.DataTypeCode === 'String';
  const isNumericType = formData.DataTypeCode === 'Numeric';
  const isDecimalType = formData.DataTypeCode === 'DECIMAL';
  const isDateType = formData.DataTypeCode === 'Date';
  
  // Dynamic field visibility based on CSV attributes (Gap Fix #2, #3, #4)
  // Check if current DataTypeCode is in the CSV list (matching legacy logic)
  const isInCSVList = (csv, dataTypeCode) => {
    if (!csv || !dataTypeCode) return false;
    const list = csv.split(',').map(item => item.trim());
    return list.includes(dataTypeCode);
  };
  
  // Gap Fix #4: Number of Lines - only show if DataTypeCode is in RequiresNumberOfLinesCSV
  const showMultiLineNumber = isInCSVList(requiresNumberOfLinesCSV, formData.DataTypeCode);
  
  // Gap Fix #3: Allow Negatives - only show if DataTypeCode is in RequiresAllowNegativeCSV
  const showAllowNegativeValues = isInCSVList(requiresAllowNegativeCSV, formData.DataTypeCode);
  
  // Gap Fix #2: Format Mask - only show if DataTypeCode is in RequiresFormatPatternCSV
  const showFormatMask = isInCSVList(requiresFormatPatternCSV, formData.DataTypeCode);

  const drawerActions = [
    {
      text: 'Cancel',
      variant: 'outlined',
      color: 'inherit',
      onClick: onClose,
      disabled: saving,
      handlerType: 'custom'
    },
    {
      text: saving ? 'Saving...' : (formData.Id ? 'Update' : 'Add'),
      variant: 'contained',
      color: 'primary',
      onClick: handleSave,
      disabled: saving,
      handlerType: 'custom'
    }
  ];

  return (
    <FAWThemeProvider>
      <FAWDrawer
        open={open}
        onClose={onClose}
        title={formData.Id ? 'Edit Additional Field' : 'Add Additional Field'}
        width={400}
        anchor="right"
        variant="temporary"
        showCloseButton={true}
        showHeader={true}
        actions={drawerActions}
      >
        <Box sx={{ 
          p: 3, 
          display: 'flex',
          flexDirection: 'column',
          gap: 3,
          position: 'relative'
        }}>
          {saving && (
            <Box sx={{ 
              position: 'absolute',
              top: 0,
              left: 0,
              right: 0,
              bottom: 0,
              display: 'flex',
              justifyContent: 'center',
              alignItems: 'center',
              backgroundColor: 'rgba(255, 255, 255, 0.8)',
              zIndex: 1000,
              borderRadius: '8px'
            }}>
              <FAWLoader />
            </Box>
          )}
          
          {loadingModel ? (
            <Box sx={{ display: 'flex', justifyContent: 'center', py: 4 }}>
              <FAWLoader />
            </Box>
          ) : (
            <>
              {errors.general && (
                <FAWAlert 
                  severity="error" 
                  message={errors.general}
                  sx={{ mb: 2 }}
                />
              )}

              <FAWInput
                label="Name"
                value={formData.Name}
                onChange={(e) => handleInputChange('Name', e.target.value)}
                placeholder="Enter field name"
                error={errors.Name}
                required
                labelSx={{ fontWeight: 500, fontSize: '14px' }}
                fullWidth
              />

              <FAWTextarea
                label="Description"
                value={formData.Description}
                onChange={(e) => handleInputChange('Description', e.target.value)}
                placeholder="Enter field description"
                rows={3}
              />

              <Box sx={{ display: 'flex', flexDirection: 'column', gap: 2 }}>
                <FAWCheckbox
                  label="Active"
                  checked={formData.Active}
                  onChange={(e) => handleCheckboxChange('Active', e.target.checked)}
                />
                <FAWCheckbox
                  label="Is Read-only?"
                  checked={formData.IsReadOnly}
                  onChange={(e) => handleCheckboxChange('IsReadOnly', e.target.checked)}
                />
              </Box>

              <FAWDropdown
                label="Data Type"
                options={normalizeOptions(dataTypeOptions)}
                value={formData.DataTypeCode || ''}
                onChange={(selectedOption) => handleInputChange('DataTypeCode', selectedOption?.value || '')}
                placeholder={optionsLoading ? "Loading..." : "Choose an option"}
                disabled={optionsLoading || (dataTypeOptions.length === 0 && loadingModel)}
                loading={optionsLoading || (dataTypeOptions.length === 0 && loadingModel)}
                required
                error={errors.DataTypeCode}
                fullWidth
              />

              {isDomainType && (
                <FAWDropdown
                  label="Data Domain"
                  options={normalizeOptions(domainOptions)}
                  value={formData.DomainCode || ''}
                  onChange={(selectedOption) => handleInputChange('DomainCode', selectedOption?.value || '')}
                  placeholder={optionsLoading ? "Loading..." : "Choose an option"}
                  disabled={optionsLoading || (domainOptions.length === 0 && loadingModel)}
                  loading={optionsLoading || (domainOptions.length === 0 && loadingModel)}
                  required
                  error={errors.DomainCode}
                  fullWidth
                />
              )}

              {isStringType && (
                <FAWInput
                  label="Max Length"
                  type="number"
                  value={formData.MaxTextLength}
                  onChange={(e) => handleInputChange('MaxTextLength', parseInt(e.target.value) || 0)}
                  error={errors.MaxTextLength}
                  labelSx={{ fontWeight: 500, fontSize: '14px' }}
                  fullWidth
                />
              )}

              {showMultiLineNumber && (
                <FAWInput
                  label="Number of Lines"
                  type="number"
                  value={formData.MultiLineNumber}
                  onChange={(e) => handleInputChange('MultiLineNumber', parseInt(e.target.value) || 0)}
                  error={errors.MultiLineNumber}
                  labelSx={{ fontWeight: 500, fontSize: '14px' }}
                  fullWidth
                />
              )}

              {isNumericType && (
                <>
                  <FAWInput
                    label="Low Value"
                    type="number"
                    value={formData.LowRange}
                    onChange={(e) => handleInputChange('LowRange', e.target.value)}
                    error={errors.LowRange}
                    labelSx={{ fontWeight: 500, fontSize: '14px' }}
                    fullWidth
                  />
                  <FAWInput
                    label="High Value"
                    type="number"
                    value={formData.HighRange}
                    onChange={(e) => handleInputChange('HighRange', e.target.value)}
                    error={errors.HighRange}
                    labelSx={{ fontWeight: 500, fontSize: '14px' }}
                    fullWidth
                  />
                </>
              )}

              {(isNumericType || isDecimalType) && (
                <FAWInput
                  label="Decimal Precision"
                  type="number"
                  value={formData.DecimalPlacesNumber}
                  onChange={(e) => handleInputChange('DecimalPlacesNumber', parseInt(e.target.value) || 0)}
                  error={errors.DecimalPlacesNumber}
                  labelSx={{ fontWeight: 500, fontSize: '14px' }}
                  fullWidth
                />
              )}

              <Box>
                {isDomainType ? (
                  <FAWDropdown
                    label="Default Value"
                    options={loadingDefaults ? [] : normalizeOptions(defaultValueOptions)}
                    value={formData.DefaultValueCode || ''}
                    onChange={(selectedOption) => handleInputChange('DefaultValueCode', selectedOption?.value || '')}
                    placeholder={loadingDefaults ? "Loading..." : "Choose an option"}
                    disabled={loadingDefaults}
                    loading={loadingDefaults}
                    fullWidth
                  />
                ) : formData.DataTypeCode === 'MULTILIST' ? (
                  <Box>
                    <FAWTypography variant="body2" sx={{ mb: 1, fontWeight: 500 }}>
                      Default Value
                    </FAWTypography>
                    <Box sx={{ 
                      maxHeight: 200, 
                      overflow: 'auto', 
                      border: '1px solid #e0e0e0', 
                      borderRadius: '8px', 
                      p: 2 
                    }}>
                      {loadingDefaults ? (
                        <FAWTypography variant="body2" color="text.secondary">
                          Loading...
                        </FAWTypography>
                      ) : (
                        normalizeOptions(defaultValueOptions).map((option) => (
                          <FAWCheckbox
                            key={option.value}
                            label={option.label}
                            checked={formData.DefaultValues.includes(option.value)}
                            onChange={(e) => handleDefaultValueChange(option.value, e.target.checked)}
                          />
                        ))
                      )}
                    </Box>
                  </Box>
                ) : isDateType ? (
                  <Box>
                    <FAWTypography variant="body2" sx={{ mb: 1, fontWeight: 500, fontSize: '14px' }}>
                      Default Value
                    </FAWTypography>
                    <Box sx={{ 
                        width: '100%', 
                        '& .react-datepicker-wrapper, & .react-datepicker__input-container, & .react-datepicker__input-container input': 
                          { width: '100%', maxWidth: '100% !important' },
                        '& .react-datepicker__input-container input' : {
                          borderRadius: '8px',
                          fontFamily: '"Plus Jakarta Sans Variable", -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif, "Apple Color Emoji", "Segoe UI Emoji", "Segoe UI Symbol" !important'
                        }
                      }}>
                      <DatePicker
                        selected={formData.DefaultValue ? moment(formData.DefaultValue, 'MM/DD/YYYY').toDate() : null}
                        onChange={(date) => {
                          const formattedDate = date ? moment(date).format('MM/DD/YYYY') : '';
                          handleInputChange('DefaultValue', formattedDate);
                        }}
                        dateFormat="MM/dd/yyyy"
                        className="form-control"
                        popperPlacement="bottom-start"
                        popperClassName="atlas-datepicker-wide-calendar"
                        placeholderText="Select a date"
                      />
                    </Box>
                  </Box>
                ) : (
                  <FAWInput
                    label="Default Value"
                    value={formData.DefaultValue}
                    onChange={(e) => handleInputChange('DefaultValue', e.target.value)}
                    placeholder="Enter default value"
                    labelSx={{ fontWeight: 500, fontSize: '14px' }}
                    fullWidth
                  />
                )}
              </Box>

              {showAllowNegativeValues && (
                <FAWCheckbox
                  label="Allow Negatives?"
                  checked={formData.AllowNegativeValues}
                  onChange={(e) => handleCheckboxChange('AllowNegativeValues', e.target.checked)}
                />
              )}

              {showFormatMask && (
                <FAWInput
                  label="Format Mask"
                  value={formData.FormatMask}
                  onChange={(e) => handleInputChange('FormatMask', e.target.value)}
                  placeholder="Enter format mask (e.g., ###-##-####)"
                  labelSx={{ fontWeight: 500, fontSize: '14px' }}
                  fullWidth
                />
              )}
            </>
          )}
        </Box>
      </FAWDrawer>

      {/* Toast Notifications */}
      <FAWToast
        open={toast.open}
        message={toast.message}
        type={toast.type}
        position="top-right"
        showCloseButton={true}
        duration={5000}
        onClose={() => setToast(prev => ({ ...prev, open: false }))}
      />
    </FAWThemeProvider>
  );
};

export default FieldEditorDrawer;
